def is_armstrong(number):
    if not isinstance(number, int) or number < 0:
        return False

    num_str = str(number)
    n = len(num_str)
    sum_of_powers = 0

    for digit_char in num_str:
        digit = int(digit_char)
        sum_of_powers += digit ** n

    return sum_of_powers == number
